        content: "Refresh token flow:\n```csharp\n// Stocare refresh token in db:\npublic class RefreshToken {\n  public int Id { get; set; }\n  public string Token { get; set; } = \"\";\n  public DateTime ExpiresAt { get; set; }\n  public bool IsRevoked { get; set; }\n  public string UserId { get; set; } = \"\";\n}\n\n// Endpoint refresh:\n[HttpPost(\"refresh\")]\npublic async Task<IActionResult> Refresh(RefreshRequest req) {\n  var stored = await _db.RefreshTokens\n    .FirstOrDefaultAsync(t => t.Token == req.RefreshToken);\n  if (stored == null || stored.IsRevoked || stored.ExpiresAt < DateTime.UtcNow)\n    return Unauthorized();\n\n  stored.IsRevoked = true; // token rotation\n  var user = await _userManager.FindByIdAsync(stored.UserId);\n  var newTokens = await GenerateTokenPair(user!);\n  await _db.SaveChangesAsync();\n  return Ok(newTokens);\n}\n```\n\nPolicy custom:\n```csharp\nbuilder.Services.AddAuthorization(opts => {\n  opts.AddPolicy(\"AdminOrOwner\", policy =>\n    policy.RequireAssertion(ctx =>\n      ctx.User.IsInRole(\"Admin\") ||\n      ctx.User.FindFirst(\"sub\")?.Value == resourceOwnerId));\n});\n```"
